void write_container_to_stream(hexi::pmc::binary_stream_writer& writer, const std::vector<uint32_t>& container) {
    // Use the prefixed adaptor to write the container with a count prefix
    writer << hexi::pmc::prefixed(container);
}

std::vector<uint32_t> read_container_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Create an empty vector to store the result
    std::vector<uint32_t> result;

    // Use the prefixed adaptor to read the container with a count prefix
    reader >> hexi::pmc::prefixed(result);

    // Return the populated vector
    return result;
}
```

