#include <cstdint>

bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Use the can_write_seek() method to check if the buffer supports write seeking
    return buffer.can_write_seek();
}

void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, hexi::buffer_seek direction, std::size_t offset) {
    // Use the write_seek() method to move the write position based on the direction and offset
    buffer.write_seek(direction, offset);
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Save current position by seeking absolutely to current position (using size() as current position)
    std::size_t current_pos = buffer.size();
    buffer.write_seek(hexi::buffer_seek::sk_absolute, current_pos);

    // Write header placeholder at the beginning
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);
    uint32_t placeholder = 0;
    buffer.write(&placeholder, sizeof(placeholder));

    // Write body data (example: 10 bytes of zeros)
    std::vector<std::byte> body_data(10, std::byte{0});
    buffer.write(body_data.data(), body_data.size());

    // Seek back to beginning to update header
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Write the actual header value
