    uint16_t header;
    std::string data;
    uint32_t footer;
};

std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    // Create a Hexi::Buffer object to store the serialized data
    Hexi::Buffer buffer;

    // Create a Hexi::BinaryStream object using the buffer
    Hexi::BinaryStream stream(buffer);

    // Use the stream's operator<< to write the header and data (which will automatically write the length prefix)
    stream << packet.header;
    stream << packet.data;

    // Use the stream's fill<16>(0x00) method to write 16 bytes of padding
    stream.fill<16>(0x00);

    // Use the stream's operator<< to write the footer
    stream << packet.footer;

    // Return the buffer's data as a vector<uint8_t>
    return std::vector<uint8_t>(buffer.data(), buffer.data() + buffer.size());
}
