        }

        auto converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(&converted_pressure, sizeof(converted_pressure));
    }

    void deserialise(auto& adaptor) {
        // Deserialization: read sensor_id, read temperatures and pressure, convert using little_to_native_inplace
        adaptor.read(&sensor_id, sizeof(sensor_id));

        // Read the number of temperatures (assuming it was stored as a prefix)
        uint32_t temp_count;
        adaptor.read(&temp_count, sizeof(temp_count));
        hexi::endian::little_to_native_inplace(temp_count);

        temperatures.resize(temp_count);
        for (auto& temp : temperatures) {
            adaptor.read(&temp, sizeof(temp));
            hexi::endian::little_to_native_inplace(temp);
        }

        adaptor.read(&pressure, sizeof(pressure));
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create a buffer and buffer_adaptor
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create binary_stream for writing
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Serialize the data
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData data;

    // Create buffer_adaptor for the input buffer
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    // Create binary_stream for reading
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Deserialize the data
    stream.deserialise(data);

    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;

    // Create buffer_adaptor for the input buffer
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Use view to extract null-terminated sensor name
    info.sensor_name = stream.view();

    // Use enforce_read_bounds to check if there's enough data for sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(&info.sensor_id, sizeof(info.sensor_id));

    // Skip remaining data
    stream.skip(buffer.size() - stream.total_read());

    return info;
}
